package CircularImport {

	package P1 {
		public import P2::*;
		part def A;
	}
	package P2 {
		public import P1::*;
		part def B;
	}
	package Test1 {
		public import P1::*;
		part x: A;
		part y: B;
	}
	package Test2 {
		public import P2::*;
		part x: A;
		part y: B;
	}

	part x: P1::A;

	// The following should not fail.
	part y: P1::B;

}

package PrivateImportTest {
	package P1 {
		part def A;
	}
	package P2 {
		private import P1::*;
	}

	part x: P1::A;

	public import P2::*;
	// This should fail.
	// A is not visible, because the import in P2 is private.
	// part y: A;
	// part y1: P2::A;

	package P3 {
		part def B;
	}

	private import P3::*;

	// This should not fail.
	// Private import only restricts visibility outside the package.
	part z: B;

	package P4 {
		public import all P2::*;

		// This should not fail because "import all" overrides private import.
		part z1: A;
	}	
}

package QualifiedNameImportTest {
	package P1 {
		part def A;
	}
	package P2 {
		package P2a {
			public import P1::*;
		}
		// The following should not fail.
		// A is a member of P2a because of the import.
		part x: P2a::A;
	}
}

