package 'Change and Time Triggers' {
	private import ISQ::TemperatureValue;
	private import ISQ::DurationValue;
	private import Time::TimeInstantValue;
	private import SI::h;

	attribute def OverTemp;

	part def Vehicle {
		attribute maintenanceTime : TimeInstantValue;
		attribute maintenanceInterval : DurationValue;
		attribute maxTemperature : TemperatureValue;
	}

	part def VehicleController;

	action senseTemperature { out temp : TemperatureValue; }

	state healthStates {
		in vehicle : Vehicle;
		in controller : VehicleController;

		first start then normal;
		do senseTemperature;

		state normal;
		accept at vehicle.maintenanceTime
			then maintenance;
		accept when senseTemperature.temp > vehicle.maxTemperature
			do send new OverTemp() to controller 
			then degraded;

		state maintenance {
			entry assign vehicle.maintenanceTime := vehicle.maintenanceTime + vehicle.maintenanceInterval;
		}
		accept after 48 [h]
			then normal;

		state degraded;
		accept when senseTemperature.temp <= vehicle.maxTemperature
			then normal;
	}
}

package 'Local Clock Example' {
	private import ScalarValues::String;

	item def Start;
	item def Request;

	part def Server {
		part :>> localClock = new Time::Clock();

		attribute today : String;

		port requestPort;

		state ServerBehavior {
			first start then off;

			state off;
			accept Start via requestPort
				then waiting;

			state waiting;
			accept request : Request via requestPort
				then responding;
			accept at new Time::Iso8601DateTime(today + "11:59:00")
				then off;

			state responding;
			accept after 5 [SI::min]
				then waiting;
		}
	}
}

