					 * the state, a "do" action that is performed while in the state
					 * and an "exit" action that is performed on exit from the state.
					 */

					entry 'perform self test';
					do 'provide power';
					exit 'apply parking brake';
				}

				transition 'on-off'
					first on
					accept 'Vehicle Off Signal'
					then off;
			}

