		#mitigation connect 'Glucose Meter in Use' to req3;

		#fmea item 'Glucose Meter in Use' : 'Glucose FMEA Item' {

			part 'glucose meter' {
				event 'glucose level undetected'[*];
				part battery {
					event 'battery depleted'[*];
					event 'battery cannot be charged'[*];
				}
				part pump;
				part reservoir;
			}

			part patient {
				event 'therapy delay'[*];
			}
		}

	}
