	public import Usages::*;

	package Definitions {
		alias Torque for ISQ::TorqueValue;

		// ATTRIBUTE DEFINITIONS

		attribute def FuelCmd;

		attribute def EngineStart;
		attribute def EngineOff;

		// ACTION DEFINITIONS

		action def 'Generate Torque' { in fuelCmd: FuelCmd; out engineTorque: Torque; }
		action def 'Amplify Torque' { in engineTorque: Torque; out transmissionTorque: Torque; }
		action def 'Transfer Torque' { in transmissionTorque: Torque; out driveshaftTorque: Torque; }
		action def 'Distribute Torque' { in driveShaftTorque: Torque; out wheelTorque1: Torque; out wheelTorque2: Torque; }

		action def 'Provide Power' { in fuelCmd: FuelCmd; out wheelTorque1: Torque; out wheelTorque2: Torque; }

	}

	package Usages {

		action 'provide power': 'Provide Power' {
			// PARAMETERS

			in fuelCmd: FuelCmd; 
			out wheelTorque1: Torque; 
			out wheelTorque2: Torque;

			loop {
				accept engineStart : EngineStart;
				then action {
					action 'generate torque': 'Generate Torque' {
						in fuelCmd = 'provide power'::fuelCmd;
						out engineTorque: Torque;
					}

					flow 'generate torque'.engineTorque 
					    to 'amplify torque'.engineTorque;

					action 'amplify torque': 'Amplify Torque' {
						in engineTorque: Torque;
						out transmissionTorque: Torque;
					}

					flow 'amplify torque'.transmissionTorque 
					    to 'transfer torque'.transmissionTorque;

					action 'transfer torque': 'Transfer Torque' {
						in transmissionTorque: Torque; 
						out driveshaftTorque: Torque;
					}

					flow 'transfer torque'.driveshaftTorque 
					    to 'distribute torque'.driveshaftTorque;

					action 'distribute torque': 'Distribute Torque' {
						in driveshaftTorque: Torque;
						out wheelTorque1: Torque;
						out wheelTorque2: Torque;
					}
				}
				then action accept engineOff : EngineOff;
			}	
		}

	}
}

package '3c-Function-based Behavior-structure mod-1' {

	part def Vehicle;
	part def VehicleFrame;

	part def HitchBall;
	part def TrailerCoupler;

	part def Trailer;
	part def TrailerFrame;

	connection def TrailerHitch {
		end hitch : HitchBall;
		end coupler : TrailerCoupler;
	}

	part 'vehicle-trailer system' {

		part vehicle : Vehicle {
			part vehicleFrame : VehicleFrame {
				part hitch : HitchBall;
			}
		}

		connection trailerHitch : TrailerHitch[0..1]
			connect vehicle.vehicleFrame.hitch to trailer.trailerFrame.coupler;

		part trailer : Trailer {
			part trailerFrame : TrailerFrame {
				part coupler : TrailerCoupler;
			}
		}

		action {
			// Create a link and assign it as the TrailerHitch connection.
			// Link participants are determined from inherited ends.
			action 'connect trailer to vehicle'
				assign 'vehicle-trailer system'.trailerHitch := new TrailerHitch();

			// Destroy the link object.
			then action 'destroy connection of trailer to vehicle' : 
				OccurrenceFunctions::destroy {
				inout occ = 'vehicle-trailer system'.trailerHitch;
			}

			// Remove the link from the TrailerHitch connection.
			then action 'disconnect trailer from vehicle'
				assign 'vehicle-trailer system'.trailerHitch := null;
		}	
	}	
}

